import numpy as np

def hardware_efficient_layer(state, params, num_qubits):
    dim = 2 ** num_qubits

    def ry(theta):
        return np.array([[np.cos(theta/2), -np.sin(theta/2)],
                        [np.sin(theta/2), np.cos(theta/2)]])

    def rz(theta):
        return np.array([[np.exp(-1j*theta/2), 0],
                        [0, np.exp(1j*theta/2)]])

    def tensor_product(ops):
        result = ops[0]
        for op in ops[1:]:
            result = np.kron(result, op)
        return result

    def apply_single_gate(s, gate, qubit):
        ops = [np.eye(2)] * num_qubits
        ops[qubit] = gate
        return tensor_product(ops) @ s

    def apply_cnot(s, ctrl, tgt):
        new_s = s.copy()
        for i in range(dim):
            if (i >> (num_qubits - 1 - ctrl)) & 1:
                j = i ^ (1 << (num_qubits - 1 - tgt))
                new_s[i], new_s[j] = s[j], s[i]
        return new_s

    # Rotation layer
    for q in range(num_qubits):
        state = apply_single_gate(state, ry(params[2*q]), q)
        state = apply_single_gate(state, rz(params[2*q + 1]), q)

    # CNOT layer
    for q in range(num_qubits - 1):
        state = apply_cnot(state, q, q + 1)

    return state

# Test
num_qubits = 3
state = np.zeros(2**num_qubits, dtype=complex)
state[0] = 1.0
params = np.random.randn(2 * num_qubits)
out_state = hardware_efficient_layer(state, params, num_qubits)
print(f"Output state norm: {np.linalg.norm(out_state):.4f}")

import numpy as np

def design_classification_qnn(num_features, num_qubits=None):
    # Determine qubit count
    if num_qubits is None:
        # At least enough to encode features, plus 1 for classification
        num_qubits = max(num_features, int(np.ceil(np.log2(num_features + 1))) + 1)

    # Layer count based on qubits (heuristic: 2-3 layers per qubit)
    num_layers = min(2 * num_qubits, 10)

    # Choose encoding based on feature count
    if num_features <= num_qubits:
        encoding = 'angle'  # One feature per qubit
    else:
        encoding = 'amplitude'  # All features in amplitudes

    # Entanglement: linear for small, circular for medium
    if num_qubits <= 4:
        entanglement = 'linear'
    elif num_qubits <= 8:
        entanglement = 'circular'
    else:
        entanglement = 'linear'  # Full too expensive

    # Total parameters
    params_per_layer = 2 * num_qubits  # Ry + Rz per qubit
    total_params = params_per_layer * (num_layers + 1)  # +1 for final layer

    return {
        'num_qubits': num_qubits,
        'num_features': num_features,
        'num_layers': num_layers,
        'encoding': encoding,
        'entanglement': entanglement,
        'measurement': 'expectation_Z_qubit_0',
        'total_params': total_params,
        'gates_per_layer': {
            'rotations': 2 * num_qubits,
            'cnots': num_qubits - 1 if entanglement == 'linear' else num_qubits
        }
    }

spec = design_classification_qnn(num_features=4)
for k, v in spec.items():
    print(f"{k}: {v}")
